from web3 import Web3
import json

class EthereumAuth:
    def __init__(self, provider_url):
        self.w3 = Web3(Web3.HTTPProvider(provider_url))

    def verify_signature(self, signature, message):
        try:
            address = self.w3.eth.account.recoverHash(message, signature=signature)
            return True
        except ValueError as e:
            print(f"Error: {str(e)}")
            return False

def authenticate(request):
    data = json.loads(request.get_json())
    signature = data['signature']
    message = data['message']

    auth_service = EthereumAuth('https://mainnet.infura.io/v3/YOUR_PROJECT_ID') # Replace with your project ID
    is_valid = auth_service.verify_signature(signature, message)

    return {'valid': is_valid}